class Solution {
    public int maxStability(int n, int[][] edges, int k) {
        Arrays.sort(edges, (a, b) -> a[2] - b[2]);
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
        int mustEdges = 0, totalEdges = 0;
        int minStrength = Integer.MAX_VALUE;
        for (int[] edge : edges) {
            int u = edge[0], v = edge[1], strength = edge[2], must = edge[3];
            if (must == 1) {
                mustEdges++;
            }
            if (union(parent, u, v)) {
                totalEdges++;
                minStrength = Math.min(minStrength, strength);
                if (must == 0) {
                    k--;
                }
            }
            if (totalEdges == n - 1) {
                break;
            }
        }
        if (totalEdges < n - 1) {
            return -1;
        }
        int low = 1, high = 100000;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (check(edges, n, k, mid)) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return high;
    }

    private boolean check(int[][] edges, int n, int k, int target) {
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
        int mustEdges = 0, totalEdges = 0;
        for (int[] edge : edges) {
            int u = edge[0], v = edge[1], strength = edge[2], must = edge[3];
            if (must == 1) {
                mustEdges++;
            }
            if (strength >= target || (strength * 2 >= target && k > 0)) {
                if (union(parent, u, v)) {
                    totalEdges++;
                    if (strength < target) {
                        k--;
                    }
                }
            }
        }
        return totalEdges == n - 1;
    }

    private int find(int[] parent, int x) {
        if (parent[x] != x) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }

    private boolean union(int[] parent, int x, int y) {
        int rootX = find(parent, x);
        int rootY = find(parent, y);
        if (rootX == rootY) {
            return false;
        }
        parent[rootX] = rootY;
        return true;
    }
}
